import type {
  CanvasNodeInteractionState,
  CanvasNodeVisualStatusTone,
} from "@workspace/ui/components/canvas-node/canvas-node";
import type { ReactNode } from "react";

export type ContainerNodeMetricKey = "cpu" | "memory";

export type ContainerNodeMetricValue = number | string;

export type ContainerNodeStatusTone =
  | "available"
  | "binding"
  | "bound"
  | "complete"
  | "creating"
  | "degraded"
  | "deleting"
  | "error"
  | "failed"
  | "inaccessible"
  | "not-configured"
  | "paused"
  | "pending"
  | "progressing"
  | "ready"
  | "reconciling"
  | "restarting"
  | "running"
  | "shutdown"
  | "starting"
  | "stopped"
  | "stopping"
  | "succeeded"
  | "suspended"
  | "unconfigured"
  | "unavailable"
  | "unhealthy"
  | "unknown"
  | "updating"
  | (string & {});

export interface ContainerNodeStatus {
  label: string;
  tone?: ContainerNodeStatusTone;
  visualTone?: CanvasNodeVisualStatusTone;
}

export interface ContainerNodeStates {
  image: string;
  kind?: string;
  metrics?: Partial<Record<ContainerNodeMetricKey, ContainerNodeMetricValue>>;
  name: string;
  namespace?: string;
  replicas?: number;
  status?: ContainerNodeStatus;
  uid?: string;
}

export type ContainerNodeQuickActionKey =
  | "calendar"
  | "console"
  | "logs"
  | "metrics";

export type ContainerNodeLifecycleActionKey =
  | "delete"
  | "restart"
  | "start"
  | "stop";

export interface ContainerNodeAction {
  disabled?: boolean;
  loading?: boolean;
  onClick?: () => Promise<void> | void;
}

export type ContainerNodeQuickActions = Partial<
  Record<ContainerNodeQuickActionKey, ContainerNodeAction>
>;

export type ContainerNodeLifecycleActions = Partial<
  Record<ContainerNodeLifecycleActionKey, ContainerNodeAction>
>;

export interface ContainerNodeActions {
  lifecycleActions?: ContainerNodeLifecycleActions;
  quickActions?: ContainerNodeQuickActions;
}

export interface ContainerNodeState {
  states: ContainerNodeStates;
}

export interface ContainerNodeContextValue {
  actions: ContainerNodeActions;
  state: ContainerNodeState;
}

export interface ContainerNodeProviderProps {
  children?: ReactNode;
  value: ContainerNodeContextValue;
}

export interface ContainerNodeRootProps {
  children?: ReactNode;
  copiedFeedbackMs?: number;
  defaultExpanded?: boolean;
  expanded?: boolean;
  interaction?: CanvasNodeInteractionState;
  lifecycleActions?: ContainerNodeLifecycleActions;
  onExpandedChange?: (expanded: boolean) => void;
  quickActions?: ContainerNodeQuickActions;
  states: ContainerNodeStates;
}

"use client";

import { createContext, use } from "react";

import type { ContainerNodeContextValue } from "./container-node.types";

export const ContainerNodeContext =
  createContext<ContainerNodeContextValue | null>(null);

export function useContainerNode(): ContainerNodeContextValue {
  const value = use(ContainerNodeContext);

  if (!value) {
    throw new Error(
      "ContainerNode: compound components must be used within ContainerNode.Root"
    );
  }

  return value;
}

"use client";

import { ContainerNodeContext } from "./container-node.context";
import type { ContainerNodeProviderProps } from "./container-node.types";

export function ContainerNodeProvider({
  children,
  value,
}: ContainerNodeProviderProps) {
  return <ContainerNodeContext value={value}>{children}</ContainerNodeContext>;
}

"use client";

import {
  CANVAS_NODE_DEFAULT_COPIED_FEEDBACK_MS,
  CanvasNodeCopyFeedbackScope,
} from "@workspace/ui/components/canvas-node/canvas-node.copyable-row";
import { CanvasNodeRoot } from "@workspace/ui/components/canvas-node/canvas-node.root";

import { ContainerNodeProvider } from "./container-node.provider";
import type {
  ContainerNodeContextValue,
  ContainerNodeRootProps,
} from "./container-node.types";

export function ContainerNodeRoot({
  children,
  copiedFeedbackMs = CANVAS_NODE_DEFAULT_COPIED_FEEDBACK_MS,
  defaultExpanded,
  expanded,
  interaction,
  lifecycleActions,
  onExpandedChange,
  quickActions,
  states,
}: ContainerNodeRootProps) {
  const value: ContainerNodeContextValue = {
    actions: {
      lifecycleActions,
      quickActions,
    },
    state: {
      states,
    },
  };

  return (
    <CanvasNodeRoot
      defaultExpanded={defaultExpanded}
      expanded={expanded}
      interaction={interaction}
      onExpandedChange={onExpandedChange}
    >
      <CanvasNodeCopyFeedbackScope copiedFeedbackMs={copiedFeedbackMs}>
        <ContainerNodeProvider value={value}>{children}</ContainerNodeProvider>
      </CanvasNodeCopyFeedbackScope>
    </CanvasNodeRoot>
  );
}

import type {
  CanvasNodeStatus,
  CanvasNodeVisualStatusTone,
} from "@workspace/ui/components/canvas-node/canvas-node";

import type { ContainerNodeStatus } from "./container-node.types";

const POSITIVE_STATUSES = new Set([
  "accessible",
  "available",
  "bound",
  "complete",
  "ready",
  "running",
  "succeeded",
]);

const PROGRESS_STATUSES = new Set([
  "binding",
  "creating",
  "pending",
  "progressing",
  "reconciling",
  "restarting",
  "starting",
  "updating",
]);

const WARNING_STATUSES = new Set(["degraded", "deleting", "stopping"]);

const NEGATIVE_STATUSES = new Set([
  "error",
  "failed",
  "inaccessible",
  "unavailable",
  "unhealthy",
]);

const NEUTRAL_STATUSES = new Set([
  "not-configured",
  "paused",
  "shutdown",
  "stopped",
  "suspended",
  "unconfigured",
  "unknown",
]);

function normalizeContainerStatusTone(input: string | undefined) {
  return input
    ?.trim()
    .toLowerCase()
    .replace(/[\s_]+/g, "-");
}

export function resolveContainerNodeVisualTone(
  status: ContainerNodeStatus | undefined
): CanvasNodeVisualStatusTone {
  if (status?.visualTone) {
    return status.visualTone;
  }

  const tone = normalizeContainerStatusTone(status?.tone ?? status?.label);

  if (tone && POSITIVE_STATUSES.has(tone)) {
    return "positive";
  }

  if (tone && PROGRESS_STATUSES.has(tone)) {
    return "progress";
  }

  if (tone && WARNING_STATUSES.has(tone)) {
    return "warning";
  }

  if (tone && NEGATIVE_STATUSES.has(tone)) {
    return "negative";
  }

  if (tone && NEUTRAL_STATUSES.has(tone)) {
    return "neutral";
  }

  return "neutral";
}

export function resolveContainerNodeStatus(
  status: ContainerNodeStatus | undefined
): CanvasNodeStatus {
  return {
    label: status?.label?.trim() || "Unknown",
    visualTone: resolveContainerNodeVisualTone(status),
  };
}

import type { ContainerNodeStatusTone } from "./container-node.types";

const FAILED_PHASES = new Set<ContainerNodeStatusTone>([
  "degraded",
  "error",
  "failed",
  "inaccessible",
  "unavailable",
  "unhealthy",
]);

const HEALTHY_RUNNING_PHASES = new Set<ContainerNodeStatusTone>([
  "available",
  "bound",
  "complete",
  "ready",
  "running",
  "succeeded",
]);

const PAUSED_STOPPED_PHASES = new Set<ContainerNodeStatusTone>([
  "paused",
  "shutdown",
  "stopped",
  "suspended",
]);

const TRANSIENT_PHASES = new Set<ContainerNodeStatusTone>([
  "binding",
  "creating",
  "deleting",
  "pending",
  "progressing",
  "reconciling",
  "restarting",
  "starting",
  "stopping",
  "updating",
]);

function normalizeContainerStatusTone(input: string | undefined) {
  return input
    ?.trim()
    .toLowerCase()
    .replace(/[\s_]+/g, "-") as ContainerNodeStatusTone | undefined;
}

export function containerNodeLifecycleMenuVisibility(
  tone: ContainerNodeStatusTone | string | undefined
): {
  showRestart: boolean;
  showStart: boolean;
  showStop: boolean;
} {
  const normalized = normalizeContainerStatusTone(tone);
  if (normalized != null && TRANSIENT_PHASES.has(normalized)) {
    return { showStart: false, showStop: false, showRestart: false };
  }
  if (normalized != null && FAILED_PHASES.has(normalized)) {
    return { showStart: false, showStop: false, showRestart: true };
  }
  if (normalized != null && HEALTHY_RUNNING_PHASES.has(normalized)) {
    return { showStart: false, showStop: true, showRestart: true };
  }
  if (normalized != null && PAUSED_STOPPED_PHASES.has(normalized)) {
    return { showStart: true, showStop: false, showRestart: true };
  }
  return { showStart: false, showStop: false, showRestart: false };
}

"use client";

import {
  AlertDialog,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@workspace/ui/components/alert-dialog";
import { Button } from "@workspace/ui/components/button";
import { cn } from "@workspace/ui/lib/utils";

const DELETE_TITLE = "Delete workload?";

function WorkloadDeleteCopy({ kind, name }: { kind?: string; name: string }) {
  const resolvedKind = kind?.trim();

  return (
    <>
      This will delete{" "}
      <span className="font-medium text-foreground">{name}</span>
      {resolvedKind ? (
        <>
          {" "}
          (<span className="font-mono">{resolvedKind}</span>)
        </>
      ) : null}{" "}
      from the project.
    </>
  );
}

export interface ContainerNodeDeleteDialogPanelProps {
  className?: string;
  kind?: string;
  name: string;
  onCancel: () => void;
  onConfirmDelete?: () => void;
}

export function ContainerNodeDeleteDialogPanel({
  className,
  kind,
  name,
  onCancel,
  onConfirmDelete,
}: ContainerNodeDeleteDialogPanelProps) {
  return (
    <div
      className={cn(
        "grid w-full max-w-md gap-6 rounded-xl bg-background p-6 text-sm ring-1 ring-foreground/10",
        className
      )}
    >
      <div className="flex flex-col gap-2">
        <h3 className="font-medium leading-none">{DELETE_TITLE}</h3>
        <p className="text-balance text-muted-foreground text-sm md:text-pretty">
          <WorkloadDeleteCopy kind={kind} name={name} />
        </p>
      </div>
      <div className="flex flex-col-reverse gap-2 sm:flex-row sm:justify-end">
        <Button onClick={onCancel} variant="outline">
          Cancel
        </Button>
        <Button
          className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
          onClick={() => onConfirmDelete?.()}
          type="button"
          variant="destructive"
        >
          Delete
        </Button>
      </div>
    </div>
  );
}

export interface ContainerNodeDeleteDialogProps {
  kind?: string;
  name: string;
  onConfirmDelete?: () => void;
  onOpenChange: (open: boolean) => void;
  open: boolean;
}

export function ContainerNodeDeleteDialog({
  kind,
  name,
  onConfirmDelete,
  onOpenChange,
  open,
}: ContainerNodeDeleteDialogProps) {
  return (
    <AlertDialog onOpenChange={onOpenChange} open={open}>
      <AlertDialogContent data-slot="container-node-delete-dialog">
        <AlertDialogHeader>
          <AlertDialogTitle>{DELETE_TITLE}</AlertDialogTitle>
          <AlertDialogDescription>
            <WorkloadDeleteCopy kind={kind} name={name} />
          </AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel>Cancel</AlertDialogCancel>
          <Button
            className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            onClick={() => {
              onConfirmDelete?.();
              onOpenChange(false);
            }}
            type="button"
            variant="destructive"
          >
            Delete
          </Button>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

ContainerNodeDeleteDialog.displayName = "ContainerNodeDeleteDialog";
ContainerNodeDeleteDialogPanel.displayName = "ContainerNodeDeleteDialogPanel";

"use client";

import { CanvasNode } from "@workspace/ui/components/canvas-node/canvas-node";
import { cn } from "@workspace/ui/lib/utils";
import {
  Activity,
  Box,
  CalendarDays,
  Cpu,
  FileText,
  Layers,
  MemoryStick,
  Pause,
  Play,
  RotateCcw,
  SquareTerminal,
  Trash2,
} from "lucide-react";
import { type ComponentType, type SVGProps, useState } from "react";

import { useContainerNode } from "./container-node.context";
import { ContainerNodeDeleteDialog } from "./container-node.delete-dialog";
import { containerNodeLifecycleMenuVisibility } from "./container-node.menu-visibility";
import { resolveContainerNodeStatus } from "./container-node.status";
import type {
  ContainerNodeLifecycleActionKey,
  ContainerNodeMetricKey,
  ContainerNodeMetricValue,
  ContainerNodeQuickActionKey,
} from "./container-node.types";

const METRIC_ITEMS = [
  { icon: Cpu, key: "cpu", label: "CPU" },
  { icon: MemoryStick, key: "memory", label: "Memory" },
] as const satisfies readonly {
  icon: ComponentType<SVGProps<SVGSVGElement>>;
  key: ContainerNodeMetricKey;
  label: string;
}[];

const QUICK_ACTION_ITEMS = [
  { icon: Activity, key: "metrics", label: "Open workload metrics" },
  { icon: SquareTerminal, key: "console", label: "Open console" },
  { icon: FileText, key: "logs", label: "Open logs" },
  { icon: CalendarDays, key: "calendar", label: "Open calendar" },
] as const satisfies readonly {
  icon: ComponentType<SVGProps<SVGSVGElement>>;
  key: ContainerNodeQuickActionKey;
  label: string;
}[];

interface LifecycleActionItem {
  icon: ComponentType<SVGProps<SVGSVGElement>>;
  key: ContainerNodeLifecycleActionKey;
  label: string;
  tone?: "destructive" | "info" | "muted" | "success";
}

const LIFECYCLE_ACTION_ITEMS: readonly LifecycleActionItem[] = [
  { icon: Play, key: "start", label: "Start", tone: "success" },
  { icon: Pause, key: "stop", label: "Stop", tone: "muted" },
  { icon: RotateCcw, key: "restart", label: "Restart", tone: "info" },
  { icon: Trash2, key: "delete", label: "Delete", tone: "destructive" },
] as const;

const CONTAINER_METRIC_PERCENT_FORMATTER = new Intl.NumberFormat("en-US", {
  maximumFractionDigits: 0,
});
const CONTAINER_METRIC_PERCENT_PATTERN = /^(-?\d+(?:\.\d+)?)\s*%$/;

function formatContainerSubtitle(kind: string | undefined) {
  const resolvedKind = kind?.trim() || "AP";

  return `${resolvedKind} workload`;
}

function formatContainerMetricPercent(value: number) {
  return Number.isFinite(value)
    ? `${CONTAINER_METRIC_PERCENT_FORMATTER.format(value)}%`
    : "--";
}

export function formatContainerMetricValue(
  value: ContainerNodeMetricValue | undefined
) {
  if (typeof value === "number") {
    return formatContainerMetricPercent(value);
  }

  const trimmed = value?.trim();

  if (!trimmed) {
    return "--";
  }

  const percentMatch = CONTAINER_METRIC_PERCENT_PATTERN.exec(trimmed);
  if (percentMatch) {
    return formatContainerMetricPercent(Number(percentMatch[1]));
  }

  return trimmed;
}

function formatContainerReplicas(replicas: number | undefined) {
  return typeof replicas === "number" && Number.isFinite(replicas)
    ? String(replicas)
    : "--";
}

export function ContainerNodeContent() {
  return (
    <CanvasNode.Card surfaceClassName="container-node-surface">
      <CanvasNode.Header>
        <ContainerNodeHeaderContent />
      </CanvasNode.Header>
      <CanvasNode.Body>
        <ContainerNodeBodyContent />
      </CanvasNode.Body>
      <CanvasNode.Footer>
        <ContainerNodeFooterContent />
      </CanvasNode.Footer>
    </CanvasNode.Card>
  );
}

export function ContainerNodeHeaderContent({
  className,
}: {
  className?: string;
}) {
  const {
    state: { states },
  } = useContainerNode();
  const subtitle = formatContainerSubtitle(states.kind);

  return (
    <div className={cn("flex min-w-0 flex-1 items-center gap-1.5", className)}>
      <span className="flex min-w-0 flex-1 items-center gap-1.5">
        <span className="flex size-9 shrink-0 items-center justify-center rounded-lg bg-white/5">
          <Box aria-hidden className="size-4" strokeWidth={2} />
        </span>
        <span className="flex min-w-0 flex-1 flex-col gap-1.5">
          <span
            className="min-w-0 truncate font-normal text-sm text-zinc-50 leading-5"
            title={states.name}
          >
            {states.name}
          </span>
          <span
            className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4"
            title={subtitle}
          >
            {subtitle}
          </span>
        </span>
      </span>
      <ContainerNodeHeaderMenu />
    </div>
  );
}

export function ContainerNodeBodyContent({
  className,
}: {
  className?: string;
}) {
  return (
    <div className={cn("container-node-body-content pt-2.5", className)}>
      <ContainerNodeImageRow />
      <ContainerNodeActionBar />
    </div>
  );
}

export function ContainerNodeImageRow({ className }: { className?: string }) {
  const {
    state: {
      states: { image },
    },
  } = useContainerNode();
  const copyValue = image.trim();
  const copyable = copyValue.length > 0;
  const displayImage = copyable ? copyValue : "--";

  return (
    <CanvasNode.CopyableRow
      className={cn(
        "container-node-image-row relative flex min-w-0 flex-col gap-1.5 rounded-lg bg-zinc-950/20 p-2.5 transition-colors",
        !copyable && "container-node-image-row-static",
        className
      )}
      copyAriaLabel="Copy image"
      copyable={copyable}
      copyValue={copyValue}
      data-slot="container-node-image-row"
      rowKey="image"
      title={copyable ? copyValue : undefined}
    >
      {({ copied, copyable: rowCopyable }) => (
        <>
          <div
            className={cn(
              "relative z-10 flex min-w-0 items-center justify-between gap-2",
              rowCopyable ? "pointer-events-none" : "pointer-events-auto"
            )}
          >
            <span className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4">
              Image
            </span>
          </div>
          <div
            aria-hidden={rowCopyable ? true : undefined}
            className={cn(
              "relative z-10 flex h-6 min-w-0 items-center justify-between gap-2 py-1 text-left font-mono text-xs leading-4",
              rowCopyable
                ? "pointer-events-none text-zinc-50"
                : "text-muted-foreground"
            )}
            data-copied={copied ? "true" : undefined}
            data-slot="container-node-image-value"
            title={copyable ? copyValue : undefined}
          >
            <span className="min-w-0 truncate">{displayImage}</span>
            <CanvasNode.CopyableRowIndicator />
          </div>
        </>
      )}
    </CanvasNode.CopyableRow>
  );
}

export function ContainerNodeActionBar({ className }: { className?: string }) {
  const {
    actions: { quickActions },
  } = useContainerNode();

  return (
    <CanvasNode.ActionBar className={className}>
      {QUICK_ACTION_ITEMS.map((item) => {
        const action = quickActions?.[item.key];
        const Icon = item.icon;

        return (
          <CanvasNode.ActionButton
            action={action}
            aria-label={item.label}
            key={item.key}
            title={item.label}
          >
            <Icon aria-hidden className="size-4" />
          </CanvasNode.ActionButton>
        );
      })}
    </CanvasNode.ActionBar>
  );
}

export function ContainerNodeFooterContent({
  className,
}: {
  className?: string;
}) {
  const {
    state: {
      states: { metrics, replicas, status },
    },
  } = useContainerNode();
  const visualStatus = resolveContainerNodeStatus(status);

  return (
    <div
      className={cn(
        "container-node-footer-content flex w-full min-w-0 items-center justify-between gap-2 text-xs leading-none",
        className
      )}
      data-slot="container-node-footer-content"
    >
      <CanvasNode.FooterStatus status={visualStatus} />
      <CanvasNode.Metrics>
        {METRIC_ITEMS.map((item) => {
          const Icon = item.icon;

          return (
            <CanvasNode.Metric
              key={item.key}
              label={item.label}
              value={formatContainerMetricValue(metrics?.[item.key])}
            >
              <Icon aria-hidden className="size-3.5 shrink-0" />
            </CanvasNode.Metric>
          );
        })}
        <CanvasNode.Metric
          label="Replicas"
          value={formatContainerReplicas(replicas)}
        >
          <Layers aria-hidden className="size-3.5 shrink-0" />
        </CanvasNode.Metric>
      </CanvasNode.Metrics>
    </div>
  );
}

function ContainerNodeHeaderMenu() {
  const {
    actions: { lifecycleActions },
    state: {
      states: { kind, name, status },
    },
  } = useContainerNode();
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const { showRestart, showStart, showStop } =
    containerNodeLifecycleMenuVisibility(status?.tone ?? status?.label);
  const deleteAction = lifecycleActions?.delete;

  return (
    <>
      <CanvasNode.ActionMenu aria-label="Open workload actions">
        {LIFECYCLE_ACTION_ITEMS.map((item) => {
          if (item.key === "start" && !showStart) {
            return null;
          }
          if (item.key === "stop" && !showStop) {
            return null;
          }
          if (item.key === "restart" && !showRestart) {
            return null;
          }

          const action = lifecycleActions?.[item.key];
          const menuAction =
            item.key === "delete" && action != null
              ? { ...action, onClick: () => setDeleteDialogOpen(true) }
              : action;
          const Icon = item.icon;

          return (
            <CanvasNode.ActionMenuItem
              action={menuAction}
              actionKey={item.key}
              icon={<Icon aria-hidden className="size-4" />}
              key={item.key}
              tone={item.tone}
            >
              {item.label}
            </CanvasNode.ActionMenuItem>
          );
        })}
      </CanvasNode.ActionMenu>
      <ContainerNodeDeleteDialog
        kind={kind}
        name={name}
        onConfirmDelete={deleteAction?.onClick}
        onOpenChange={setDeleteDialogOpen}
        open={deleteDialogOpen}
      />
    </>
  );
}

